document.addEventListener("DOMContentLoaded",(()=>{const e=document.getElementById("selectedCompany");e&&(e.innerHTML='<span class="header-app-style-company">Εταιρεία :</span>'),setTimeout((()=>{(async()=>{try{const t=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,n=await fetch("/api/companyDescription",{method:"GET",headers:{"Content-Type":"application/json",...t&&{"CSRF-Token":t}},credentials:"include"});if(!n.ok)throw new Error(`HTTP ${n.status}: ${n.statusText}`);const a=n.headers.get("content-type");if(!a||!a.includes("application/json"))return void await n.text();const o=await n.text();if(!o||""===o.trim())return;let s;try{s=JSON.parse(o)}catch(e){return}if(s&&s.newCompanyDescription){const t="Εταιρεία : "+s.newCompanyDescription;if(e){const n=t.length>2?t.substring(0,t.length-1):t;e.innerHTML=n}}}catch(t){e&&(e.innerHTML='<span class="header-app-style-company">Εταιρεία :</span>')}})()}),100)}));